mapper.select:
select rr.id, rr.reg_no, pa.name, pa.age, pa.gender, do.department, rr.schedule_date, rr.schedule_time, rr.create_time, rr.visit_status, rr.status as payStatus, rr.amount, rr.doctor_id as doctor_id from registration_record as rr join users as us on rr.user_id = us.id join patients as pa on rr.patient_id = pa.id join doctors as do on rr.doctor_id = do.id where pa.name like concat('%',#{name},'%')
and rr.doctor_id = #{doctorId}
order by rr.id
